pass_count = skip_count = fail_count = 0
records: list[dict] = []  # one record per cell for the agreement check

def _row_count(result):
    """Return a row count for the agreement check.

    Handles the three Python SDK return shapes:
      - `list[Tick]`          -> len(list)            (history endpoints)
      - columnar dict         -> len(any column list) (snapshot endpoints)
      - str-list              -> len(list)            (list endpoints)
      - None                   -> 0                   (void returns)
    """
    if result is None:
        return 0
    if isinstance(result, dict):
        # Columnar: each column is a list; rows = len of any column.
        for v in result.values():
            if isinstance(v, list):
                return len(v)
        return 1  # dict with no list columns (shouldn't happen in practice)
    try:
        return len(result)
    except TypeError:
        return 1

for endpoint, mode, min_tier, rationale, call in CELLS:
    label = f"{endpoint}::{mode}"
    t0 = time.monotonic()
    try:
        value = call()
    except BaseException as exc:  # noqa: BLE001
        duration_ms = int((time.monotonic() - t0) * 1000)
        msg = str(exc).lower()
        # Per-call deadline elapsed: SDK cancelled the in-flight gRPC
        # stream and raised RuntimeError carrying our timeout sentinel.
        # No daemon threads to clean up — the next cell runs immediately.
        if "request deadline exceeded" in msg:
            print(f"  {label:60s} FAIL  timeout after {duration_ms//1000}s", flush=True)
            fail_count += 1
            records.append({
                "endpoint": endpoint, "mode": mode, "rationale": rationale,
                "status": "FAIL",
                "row_count": 0, "duration_ms": duration_ms,
                "detail": f"timeout after {duration_ms//1000}s",
            })
            continue
        if "permission" in msg or "subscription" in msg:
            print(f"  {label:60s} SKIP: tier-permission (declared min_tier={min_tier})", flush=True)
            skip_count += 1
            records.append({
                "endpoint": endpoint, "mode": mode, "rationale": rationale,
                "status": "SKIP",
                "row_count": 0, "duration_ms": duration_ms, "detail": "tier-permission",
            })
            continue
        if "no data found" in msg:
            print(f"  {label:60s} PASS  (no data)", flush=True)
            pass_count += 1
            records.append({
                "endpoint": endpoint, "mode": mode, "rationale": rationale,
                "status": "PASS",
                "row_count": 0, "duration_ms": duration_ms, "detail": "no data",
            })
            continue
        # Exception messages can span multiple lines; escape them at the
        # producer so the agreement-table row stays on one line. See
        # scripts/validate_agreement.py disagreement output.
        detail = str(exc).replace("\n", "\\n").replace("\r", "\\r")[:200]
        print(f"  {label:60s} FAIL  {exc}", flush=True)
        fail_count += 1
        records.append({
            "endpoint": endpoint, "mode": mode, "rationale": rationale,
            "status": "FAIL",
            "row_count": 0, "duration_ms": duration_ms, "detail": detail,
        })
        continue
    duration_ms = int((time.monotonic() - t0) * 1000)
    row_count = _row_count(value)
    print(f"  {label:60s} PASS", flush=True)
    pass_count += 1
    records.append({
        "endpoint": endpoint, "mode": mode, "rationale": rationale,
        "status": "PASS",
        "row_count": row_count, "duration_ms": duration_ms, "detail": "",
    })

print(f"\nPython: {pass_count} PASS, {skip_count} SKIP, {fail_count} FAIL", flush=True)
print(f"COUNTS:{pass_count}:{skip_count}:{fail_count}", flush=True)
ARTIFACT_PATH.parent.mkdir(parents=True, exist_ok=True)
ARTIFACT_PATH.write_text(json.dumps({
    "lang": "python",
    "records": records,
}, indent=2, sort_keys=True))
print(f"artifact: {ARTIFACT_PATH}", flush=True)
sys.exit(1 if fail_count > 0 else 0)
